using System.ComponentModel;
using System.Drawing.Design;
using System.Windows.Forms;
using System.Windows.Forms.Design;

public class MyControl : UserControl
{
    private StatusStrip _statusStrip;

    public string DisplayName { get; set; }

    [Editor(typeof(MaxItemsEditor), typeof(UITypeEditor))]
    public int MaxItems { get; set; }

    public MyControl()
    {
        _statusStrip = new StatusStrip();
        // .NET 9 changed StatusStrip default rendering from Professional to System.
        // Restore .NET 8 appearance by explicitly setting ManagerRenderMode.
        _statusStrip.RenderMode = ToolStripRenderMode.ManagerRenderMode;
        _statusStrip.Items.Add(new ToolStripStatusLabel("Ready"));
        Controls.Add(_statusStrip);
    }
}

public class MaxItemsEditor : UITypeEditor
{
    public override UITypeEditorEditStyle GetEditStyle(ITypeDescriptorContext? context)
        => UITypeEditorEditStyle.DropDown;

    public override object? EditValue(ITypeDescriptorContext? context,
        IServiceProvider? provider, object? value)
    {
        var editorService = provider?.GetService(typeof(IWindowsFormsEditorService))
            as IWindowsFormsEditorService;
        if (editorService is null) return value;

        var control = CreateDropDownControl(value);
        // .NET 9 throws ArgumentNullException if control is null.
        if (control is not null)
        {
            editorService.DropDownControl(control);
            value = (int)((NumericUpDown)control).Value;
        }
        return value;
    }

    private static Control? CreateDropDownControl(object? currentValue)
    {
        var numeric = new NumericUpDown { Minimum = 0, Maximum = 1000 };
        if (currentValue is int v) numeric.Value = v;
        return numeric;
    }
}

